function QuoteRow({ item, onChange, onRemove }) {
  const subtotal = item.qty * item.price;
  return (
    <div style={{
      display: "grid",
      gridTemplateColumns: "2fr 80px 110px 110px 40px",
      gap: 8,
      alignItems: "center",
      padding: "8px 12px",
      background: "rgba(61,96,128,0.15)",
      borderRadius: 6,
      marginBottom: 6,
      borderLeft: `3px solid ${BRAND.orange}`,
    }}>
      <span style={{ color: "#e8f0f5", fontSize: 14 }}>{item.name}</span>
      <input
        type="number"
        min={1}
        value={item.qty}
        onChange={e => onChange({ ...item, qty: +e.target.value })}
        style={{
          background: "rgba(168,196,216,0.12)",
          border: `1px solid ${BRAND.blue_mid}`,
          borderRadius: 4,
          color: "#fff",
          padding: "4px 6px",
          textAlign: "center",
          width: "100%",
          fontSize: 14,
        }}
      />
      <input
        type="number"
        min={0}
        value={item.price}
        onChange={e => onChange({ ...item, price: +e.target.value })}
        style={{
          background: "rgba(168,196,216,0.12)",
          border: `1px solid ${BRAND.blue_mid}`,
          borderRadius: 4,
          color: BRAND.blue_light,
          padding: "4px 6px",
          textAlign: "right",
          width: "100%",
          fontSize: 13,
        }}
      />
      <span style={{ color: BRAND.orange, fontWeight: 700, textAlign: "right", fontSize: 14 }}>
        NT$ {subtotal.toLocaleString()}
      </span>
      <button
        onClick={onRemove}
        style={{
          background: "rgba(212,96,26,0.2)",
          border: "1px solid rgba(212,96,26,0.4)",
          borderRadius: 4,
          color: BRAND.orange,
          cursor: "pointer",
          fontSize: 14,
          padding: "2px 6px",
        }}
      >✕</button>
    </div>
  );
}


function CustomItemAdder({ onAdd, inputStyle, BRAND }) {
  const [name, setName] = useState("");
  const [price, setPrice] = useState("");

  const handleAdd = () => {
    if (!name || !price) return;
    onAdd({ name, unit: "式", price: +price, qty: 1 });
    const again = window.confirm(`已加入「${name}」，是否繼續新增品項？`);
    if (again) {
      setName("");
      setPrice("");
    } else {
      setName("");
      setPrice("");
    }
  };

  return (
    <div style={{ display: "flex", gap: 6, alignItems: "flex-end" }}>
      <div style={{ flex: 2 }}>
        <div style={{ color: "#a8c4d8", fontSize: 11, marginBottom: 3 }}>品項名稱</div>
        <input style={inputStyle} value={name}
          onChange={e => setName(e.target.value)}
          placeholder="自訂品項名稱" />
      </div>
      <div style={{ flex: 1 }}>
        <div style={{ color: "#a8c4d8", fontSize: 11, marginBottom: 3 }}>金額</div>
        <input type="number" style={inputStyle} value={price}
          onChange={e => setPrice(e.target.value)}
          placeholder="0" />
      </div>
      <button onClick={handleAdd} style={{
        background: BRAND.blue_deep, border: "none", borderRadius: 5,
        color: "#fff", padding: "7px 12px", cursor: "pointer", fontSize: 13,
        whiteSpace: "nowrap",
      }}>＋ 加入</button>
    </div>
  );
}

